  useEffect(() => {
    const ws = new WebSocket(`/ws/${roomId}`)
    ws.onmessage = (e) => handleNewMessage(JSON.parse(e.data))
    return () => ws.close()
  }, [roomId, handleNewMessage])

  return <div>{/* render messages */}</div>
}

Even though unreadCount changes, the callback seems frozen with the old value. What's happening?

